const ENGINE = $env.ENGINE_URL;
const SLACK = $env.SLACK_WEBHOOK_URL;
const APPROVE = $env.APPROVE_WEBHOOK_URL;
const body = ($input.first().json.body) || {};
const create = await this.helpers.httpRequest({ method: 'POST', url: ENGINE + '/jobs', body: { type: body.type || 'content_piece', brand: body.brand || {}, payload: body.payload || {} }, json: true });
const jobId = create.job_id;
const TERMINAL = ['optimized', 'failed', 'revision_needed', 'halted_budget'];
let status = create.status;
for (let i = 0; i < 60; i++) {
  const t = await this.helpers.httpRequest({ method: 'POST', url: ENGINE + '/tick', json: true });
  const j = await this.helpers.httpRequest({ method: 'GET', url: ENGINE + '/jobs/' + jobId, json: true });
  status = j.status;
  if (status === 'AWAITING_APPROVAL' || TERMINAL.includes(status)) break;
  if (!t.advanced) break;
  await new Promise(r => setTimeout(r, 300));
}
if (status === 'AWAITING_APPROVAL' && SLACK) {
  await this.helpers.httpRequest({ method: 'POST', url: SLACK, body: { text: 'Content job ' + jobId + ' is ready for approval. Approve: ' + APPROVE + '?job_id=' + jobId }, json: true });
}
return [{ json: { job_id: jobId, status: status } }];
